1	package com.fortinet.nac.ingestion.consumer.orchestrator;
2	
3	import com.fortinet.nac.common.Constants;
4	import com.fortinet.nac.common.dto.IngestionRequest;
5	import com.fortinet.nac.common.redis.DistributedLock;
6	import com.fortinet.nac.common.util.StatusOr;
7	import com.fortinet.nac.ingestion.consumer.handler.*;
8	import com.fortinet.nac.ingestion.delayqueue.RedisDelayQueueUtil;
9	import com.fortinet.nac.ingestion.entity.Entity;
10	import com.fortinet.nac.ingestion.service.EntityService;
11	import com.fortinet.nac.ingestion.util.EntityCache;
12	import com.fortinet.nac.ingestion.util.RedisUtil;
13	
14	import lombok.RequiredArgsConstructor;
15	import lombok.extern.slf4j.Slf4j;
16	import org.springframework.stereotype.Component;
17	
18	
19	@Slf4j
20	@Component
21	@RequiredArgsConstructor
22	public class IngestionOrchestrator {
23	
24	    private final EntityCache entityCache;
25	    private final EntityService entityService;
26	    private final DistributedLock distributedLock;
27	    private final RedisDelayQueueUtil redisDelayQueueUtil;
28	
29	    private final NewEntityHandler newEntityHandler;
30	    private final CachedExistingEntityHandler cachedExistingEntityHandler;
31	    private final DbExistingEntityHandler dbExistingEntityHandler;
32	
33	    private static final int MAX_REQUEUE = 5;
34	    private static final long INITIAL_BACKOFF_SEC = 2;
35	
36	    public StatusOr<Entity> process(IngestionRequest req) {
37	
38	        String existKey = RedisUtil.getExistKey(req);
39	
40	        // 1. query cache
41	        Long cachedId = entityCache.getCachedEntityId(existKey);
42	        if (cachedId != null) {
43	            log.info("Entity cache HIT for key={}", existKey);
44	            return cachedExistingEntityHandler.handle(req, cachedId);
45	        }
46	        log.info("Entity cache MISS for key={}", existKey);
47	
48	        // 2. since cache not hit, acquire creation lock
49	        String createLockKey = RedisUtil.getEntityLockKey(Constants.RedisKeys.ENTITY_CREATE_LOCK_PREFIX, req);
50	        boolean lock = distributedLock.tryLock(createLockKey, Constants.RedisKeys.ENTITY_CREATE_LOCK_TTL);
51	        if (!lock) {
52	            // No need to spin-retry the createLock; contention is caused by concurrency,
53	            // not a transient glitch that will clear shortly.
54	            return handleLockCreateKeyFailure(req);
55	        }
56	
57	        try {
58	            // 3. DB lookup
59	            Entity dbEntity = entityService.getEntity(req);
60	            log.info("Target entity {} in Entity DB", dbEntity == null ? "not found" : "found");
61	            if (dbEntity != null) {
62	                try {
63	                    entityCache.cacheEntityId(existKey, dbEntity.getId(), Constants.RedisKeys.ENTITY_EXIST_KEY_TTL);
64	                } catch (Exception ex) {
65	                    log.warn("Failed to cache entityId, degrade to DB lookup next time. key={}, entityId={}, err={}",
66	                            existKey, dbEntity.getId(), ex.toString());
67	                }
68	                return dbExistingEntityHandler.handle(req, dbEntity.getId());
69	            }
70	
71	            // 4. create new Entity
72	            return newEntityHandler.handle(req);
73	        } finally {
74	            distributedLock.unLock(createLockKey);
75	        }
76	    }
77	
78	    private StatusOr<Entity> handleLockCreateKeyFailure(IngestionRequest req) {
79	
80	        int retryCount = req.getRequeueCount();
81	
82	        // exceed max retry
83	        if (retryCount >= MAX_REQUEUE) {
84	            log.error("Too many requeue (retry={}) for req={}, treat as failed", retryCount, req);
85	            return StatusOr.error(Constants.BusinesCode.ACQUIRE_CREATE_LOCK_FAILURE,
86	                    "too many requeue for create lock");
87	        }
88	
89	        long delaySeconds = INITIAL_BACKOFF_SEC << retryCount; // 2,4,8,16,32
90	        long delayMillis = delaySeconds * 1000;
91	
92	        retryCount++;
93	        req.setRequeueCount(retryCount);
94	
95	        // send delayed msg
96	        try {
97	            redisDelayQueueUtil.enqueueWithDelay(req, delayMillis);
98	        } catch (Exception ex) {
99	            log.error("Failed to enqueue delay queue, consumer will retry. err={}", ex.toString());
100	            // let consumer retry
101	            return StatusOr.error(Constants.BusinesCode.INTERNAL_ERROR, "delay enqueue failed");
102	        }
103	
104	        log.warn("Requeue request due to lock conflict, retry={}: {}", retryCount, req);
105	        return StatusOr.error(Constants.BusinesCode.ACQUIRE_CREATE_LOCK_FAILURE, "create lock fail");
106	    }
107	}
