package com.fortinet.nac.ingestion.consumer.handler;

import com.fortinet.nac.common.Constants;
import com.fortinet.nac.common.dto.IngestionRequest;
import com.fortinet.nac.common.enums.EntityStage;
import com.fortinet.nac.common.enums.EntityType;
import com.fortinet.nac.common.redis.DistributedLock;
import com.fortinet.nac.common.util.StatusOr;
import com.fortinet.nac.ingestion.consumer.EntityAttributeFingerprintBuilder;
import com.fortinet.nac.ingestion.consumer.FingerprintBuildResult;
import com.fortinet.nac.ingestion.consumer.statemachine.EntityStateMachine;
import com.fortinet.nac.ingestion.entity.Entity;
import com.fortinet.nac.ingestion.service.EntityService;
import com.fortinet.nac.ingestion.util.EntityCache;
import com.fortinet.nac.ingestion.util.RedisUtil;

import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;

import org.springframework.stereotype.Component;

import java.time.Instant;

/**
 * Handles the case where an entity exists in cache but the incoming request
 * carries a different device type (e.g., HOST → USER_HOST_BINDING).
 *
 * This typically happens when a host that was previously seen as a standalone
 * HOST is now observed with a user binding, promoting it to USER_HOST_BINDING.
 *
 * The handler invalidates the stale cache entry, updates the existing entity's
 * type and fingerprint, resets its processing stage, and re-runs the state machine.
 */
@Slf4j
@Component
@RequiredArgsConstructor
public class DeviceTypeChangedHandler {

    private final EntityService entityService;
    private final EntityCache entityCache;
    private final DistributedLock distributedLock;
    private final EntityStateMachine stateMachine;
    private final EntityAttributeFingerprintBuilder entityAttributeFingerprintBuilder;

    public StatusOr<Entity> handle(IngestionRequest req, Entity cachedEntity) {
        EntityType oldType = cachedEntity.getType();
        EntityType newType = EntityType.valueOf(req.getEntityType());

        log.info("DeviceTypeChangedHandler: entityId={}, typeChange={} -> {}, reqId={}",
                cachedEntity.getId(), oldType, newType, req.getRequestId());

        // 1. Acquire process lock — type change is a mutating operation
        String processLockKey = RedisUtil.getEntityLockKey(Constants.RedisKeys.ENTITY_PROCESS_LOCK_PREFIX, req);
        boolean acquired = distributedLock.tryLock(processLockKey, Constants.RedisKeys.ENTITY_PROCESS_LOCK_TTL);
        if (!acquired) {
            log.warn("DeviceTypeChangedHandler: failed to acquire process lock, entityId={}, reqId={}",
                    cachedEntity.getId(), req.getRequestId());
            return StatusOr.error(Constants.BusinesCode.ACQUIRE_PROCESS_LOCK_FAILURE_AFTER_ENTITY_CREATED,
                    "process lock busy during type change");
        }

        try {
            // 2. Re-read from DB to avoid stale-cache races
            Entity dbEntity = entityService.getEntity(cachedEntity.getId());
            if (dbEntity == null) {
                log.error("DeviceTypeChangedHandler: entity disappeared from DB, entityId={}", cachedEntity.getId());
                return StatusOr.error(Constants.BusinesCode.INTERNAL_ERROR,
                        "entity not found in DB: " + cachedEntity.getId());
            }

            // 3. Rebuild fingerprint for the new type
            FingerprintBuildResult fpResult = entityAttributeFingerprintBuilder.build(req);
            String newFp = fpResult.getFingerprint();

            // 4. Update entity: type, fingerprint, reset processing state
            dbEntity.setType(newType);
            dbEntity.setAttributeFingerprint(newFp);
            dbEntity.setProcessingStage(EntityStage.PENDING.toString());
            dbEntity.setProcessingCode(0);
            dbEntity.setErrorMessage(null);
            dbEntity.setProcessingResult(null);
            dbEntity.setLastReqVersion(req.getVersion());
            dbEntity.setUpdatedAt(Instant.now());

            // For USER_HOST_BINDING, populate userIdentity
            if (newType == EntityType.USER_HOST_BINDING) {
                dbEntity.setUserId(req.getUserId());
                dbEntity.setUserIdentity(req.getUserId());
            }

            entityService.save(dbEntity);
            log.info("DeviceTypeChangedHandler: entity updated in DB, entityId={}, newType={}, newFp={}",
                    dbEntity.getId(), newType, newFp);

            // 5. Invalidate old cache and write updated entity
            String existKey = RedisUtil.getExistKey(req);
            try {
                entityCache.cacheEntity(existKey, dbEntity, Constants.RedisKeys.ENTITY_EXIST_KEY_TTL);
            } catch (Exception ex) {
                log.warn("Failed to update cache after type change, entityId={}, err={}",
                        dbEntity.getId(), ex.toString());
            }

            // 6. Re-run state machine from PENDING
            return stateMachine.start(req.getRequestId(), req.isAsync(), dbEntity);

        } finally {
            distributedLock.unLock(processLockKey);
        }
    }
}

