package com.fortinet.nac.ingestion.consumer.statemachine;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ObjectNode;

import com.fortinet.nac.common.Constants;
import com.fortinet.nac.common.util.StatusOr;
import com.fortinet.nac.common.dto.EntityDTO;
import com.fortinet.nac.ingestion.converter.EntityDTOConverter;
import com.fortinet.nac.ingestion.entity.Entity;
import com.fortinet.nac.common.enums.EntityProcessingCode;
import com.fortinet.nac.common.enums.EntityStage;
import com.fortinet.nac.common.failpoint.Failpoint;
import com.fortinet.nac.ingestion.registry.EntityProcessingRegistry;
import com.fortinet.nac.ingestion.service.EntityService;

import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Timer;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Component;

import java.util.concurrent.*;
import java.util.function.Function;

@Slf4j
@Component
@RequiredArgsConstructor
public class EntityStateMachine {
    private final EntityProcessingRegistry processingRegistry;
    private final EntityService entityService;
    private final ObjectMapper objectMapper;
    private final MeterRegistry meterRegistry;
    private final EntityDTOConverter entityDTOConverter;

    private final EntityStageTransactionRunner txRunner;

    public StatusOr<Entity> start(String requestId, boolean isAsync, Entity entity) {
        Timer.Sample sample = Timer.start(meterRegistry);
        long startTime = System.nanoTime();
        Long entityId = entity.getId();

        EntityDTO entityDTO = entityDTOConverter.fromEntity(entity);

        String resultTag = "success";

        try {
            // Register current request context
            if (!isAsync) {
                processingRegistry.register(entityId, requestId);
            }

            while (true) {
                if (entityService.isInterrupted(entityId)) {
                    log.info("Entity {} processing interrupted.", entityId);

                    resultTag = "interrupted";
                    return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_PROCESS_INTERRUPTED, "interrupted");
                }

                String stageStr = entityDTO.getProcessingStage();
                if (stageStr == null) {
                    resultTag = "fail";
                    return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_INVALID_ENTITY_STAGE,
                            "processingStage is null for entityId=" + entityId);
                }

                EntityStage stage = EntityStage.valueOf(stageStr.toUpperCase());

                int code = entityDTO.getProcessingCode() == null ? 0 : entityDTO.getProcessingCode();
                if (code != 0) {
                    log.info("Entity {} failed in stage={}, code={}", entityId, stage, code);

                    resultTag = "fail";
                    return StatusOr.ok(entityDTOConverter.toEntity(entityDTO));
                }

                boolean success = false;

                switch (stage) {
                    case PENDING:
                        success = handlePending(entityDTO);
                        break;
                    case LABELED:
                        success = handleLabeled(entityDTO);
                        break;
                    case EVALUATED:
                        success = handleEvaluated(entityDTO);
                        break;
                    case ENFORCED:
                        // completed
                        return StatusOr.ok(entityDTOConverter.toEntity(entityDTO));
                    default:
                        resultTag = "fail";
                        return StatusOr.error(Constants.BusinesCode.STATE_MACHINE_INVALID_ENTITY_STAGE,
                                "Invalid stage: " + stage);
                }

                if (!success) {
                    resultTag = "fail";
                    return StatusOr.ok(entityDTOConverter.toEntity(entityDTO));
                }
            }
        } finally {
            if (!isAsync) {
                processingRegistry.unregister(entityId);
            }
            log.info("State Machine cost {} ms", TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startTime));

            String stageStr = entityDTO.getProcessingStage();
            String finalStageTag = (stageStr == null ? "UNKNOWN" : stageStr.toUpperCase());

            Timer timer = Timer.builder("ingestion_state_machine_seconds")
                    .tag("result", resultTag)
                    .tag("finalStage", finalStageTag)
                    .register(meterRegistry);
            sample.stop(timer);
        }
    }

    /**
     * PENDING stage: call labelService
     */
    private boolean handlePending(EntityDTO dto) {
        return processStage(dto, EntityStage.LABELED, txRunner::runLabel);
    }

    /**
     * LABELED stage: call PolicyService
     */
    private boolean handleLabeled(EntityDTO dto) {
        return processStage(dto, EntityStage.EVALUATED, txRunner::runPolicy);
    }

    /**
     * EVALUATED stage: call EnforcementService
     */
    private boolean handleEvaluated(EntityDTO dto) {
        return processStage(dto, EntityStage.ENFORCED, txRunner::runEnforce);
    }


    private boolean processStage(
            EntityDTO dto,
            EntityStage nextStageEnum,
            Function<EntityDTO, ObjectNode> serviceFunction
    ) {
        long entityId = dto.getId();
        String currentStage = dto.getProcessingStage();
        String nextStage = nextStageEnum.toString();

        log.info("StateMachine: [{} -> {}] START, entityId={}",
                currentStage, nextStage, entityId);

        final int MAX_RETRY = 3;

        boolean serviceSuccess = false;

        for (int attempt = 1; attempt <= MAX_RETRY; attempt++) {
            log.info("Executing [{}] service, attempt={}, entityId={}",
                    nextStage, attempt, entityId);

            // Failpoint 1: crash before invoking downstream services
            Failpoint.crashIfEnabled(Constants.Failpoints.SM_BEFORE_SERVICE_PREFIX + nextStage);

            ObjectNode serviceResult = serviceFunction.apply(dto);

            // Failpoint 2: crash after service returns but before updating DTO/DB
            Failpoint.crashIfEnabled(Constants.Failpoints.SM_AFTER_SERVICE_PREFIX + nextStage);

            if (serviceResult == null) {
                serviceResult = objectMapper.createObjectNode();
                serviceResult.put("code", -1);
                serviceResult.put("errMessage", "null serviceResult");
            }

            int code = serviceResult.path("code").asInt();
            if (code == 0) {
                serviceSuccess = true;
                handleServiceSuccess(dto, nextStage, serviceResult, attempt);
                break;
            }

            log.warn("Stage [{}] returned non-zero code on attempt {}: code={}, err={}, entityId={}",
                    nextStage, attempt, code, serviceResult.path("errMessage").asText(), entityId);

            boolean retryable = EntityProcessingCode.isRetryableCode(nextStageEnum, code);
            if (!retryable) {
                // Non-retryable; current attempt is the final failure
                handleServiceFinalFailure(dto, nextStage, serviceResult, attempt, false);
                break;
            }
            if (attempt == MAX_RETRY) {
                // Retryable but exhausted max attempts
                handleServiceFinalFailure(dto, nextStage, serviceResult, attempt, true);
                break;
            }

            long base = 1000L * attempt;
            // avoid Thundering Herd: prevent many requests retrying at the same time
            long jitter = ThreadLocalRandom.current().nextLong(0, 100); // 0~99ms
            long sleepMs = base + jitter;
            log.info("Backoff {} ms before retrying stage [{}]...", sleepMs, nextStage);
            sleep(sleepMs);
        }

        // update stage in DTO
        dto.setProcessingStage(nextStage);
        boolean dbSuccess = updateDBEntityProcessingState(dto);

        return serviceSuccess && dbSuccess;
    }


    /**
     * Append each stage result into processingResult; real implementation may merge JSON objects
     */
    public void mergeProcessingResult(EntityDTO dto, String stageKey, JsonNode stageProcessingRes) {
        ObjectNode root = objectMapper.createObjectNode();

        String existing = dto.getProcessingResult();
        if (existing != null && !existing.isEmpty()) {
            try {
                root = (ObjectNode) objectMapper.readTree(existing);
            } catch (Exception e) {
                // Log only, do not throw, to avoid breaking the state machine
                log.error("mergeProcessingResult: invalid JSON in processingResult for entity {}, will overwrite. raw={}, err={}",
                        dto.getId(), existing, e.getMessage());
                // Keep raw content in a special field
                ObjectNode corrupt = objectMapper.createObjectNode();
                corrupt.put("raw", existing);
                root.set("_corruptProcessingResult", corrupt);
            }
        }

        // avoid NPE
        if (stageProcessingRes == null) {
            root.putNull(stageKey);
        } else {
            root.set(stageKey, stageProcessingRes);
        }

        dto.setProcessingResult(root.toString());
    }


    // just update entity in memory (DTO)
    private void handleServiceSuccess(EntityDTO dto, String nextStage, ObjectNode serviceResult, int attempt) {
        mergeProcessingResult(dto, nextStage, serviceResult.path("data"));
        dto.setProcessingCode(0);
        dto.setErrorMessage(null);

        log.info("Stage [{}] SUCCESS on attempt {}, entityId={}",
                nextStage, attempt, dto.getId());
    }

    // just update entity in memory (DTO)
    private void handleServiceFinalFailure(EntityDTO dto, String nextStage,
                                           ObjectNode serviceResult, int attempt,
                                           boolean exhaustedRetry) {
        int code = serviceResult.path("code").asInt(-1);
        dto.setProcessingCode(code);

        String msg = serviceResult.path("errMessage").asText(null);
        dto.setErrorMessage(msg);

        ObjectNode err = objectMapper.createObjectNode();
        err.put("error", msg == null ? "unknown error" : msg);
        err.put("attempt", attempt);
        err.put("exhaustedRetry", exhaustedRetry);
        mergeProcessingResult(dto, nextStage, err);

        if (exhaustedRetry) {
            log.error("Stage [{}] FAILED after exhausting retries, attempts={}, entityId={}, code={}, error={}",
                    nextStage, attempt, dto.getId(), code, msg);
        } else {
            log.error("Stage [{}] FAILED with non-retryable code, attempt={}, entityId={}, code={}, error={}",
                    nextStage, attempt, dto.getId(), code, msg);
        }
    }


    private boolean updateDBEntityProcessingState(EntityDTO dto) {
        Entity entity = entityDTOConverter.toEntity(dto);
        boolean ok = entityService.updateProcessingState(entity);
        if (!ok) {
            log.error("DB update FAILED (rows=0), stage={}, entityId={}",
                      dto.getProcessingStage(), dto.getId());
            return false;
        }

        log.info("StateMachine: [{}] DB updated, entityId={}", dto.getProcessingStage(), dto.getId());
        return true;
    }

    private void sleep(long ms) {
        try {
            Thread.sleep(ms);
        } catch (InterruptedException ignored) {
            Thread.currentThread().interrupt();
        }
    }

    // only used for tolerance testing
    private void simulateDelay(int minMs, int maxMs) {
        int delay = ThreadLocalRandom.current().nextInt(minMs, maxMs + 1);
        try {
            Thread.sleep(delay);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            throw new RuntimeException("Interrupted during simulated delay", e);
        }
    }
}

