package com.fortinet.nac.ingestion.controller;

import com.fortinet.nac.common.dto.Pagination;
import com.fortinet.nac.common.dto.ResultDTO;
import com.fortinet.nac.common.enums.ReprocessState;
import com.fortinet.nac.ingestion.dto.EntityQueryDTO;
import com.fortinet.nac.ingestion.dto.EntityStateDisplayDTO;
import com.fortinet.nac.ingestion.entity.Entity;
import com.fortinet.nac.ingestion.service.EntityService;

import org.springframework.web.bind.annotation.*;

import javax.annotation.Resource;

@RestController
@RequestMapping("/api/v1/entities")
public class EntityController {

    @Resource
    private EntityService entityService;

    @PostMapping("/query")
    public ResultDTO<Pagination<Entity>> queryFailedEntities(@RequestBody EntityQueryDTO req) {
        Pagination<Entity> page = entityService.queryFailedEntities(req);
        return ResultDTO.success(page);
    }

    @GetMapping("/{id}")
    public Entity getEntity(@PathVariable Long id) {
        return entityService.getById(id);
    }

    @GetMapping("/{id}/display-status")
    public ResultDTO<EntityStateDisplayDTO> getEntityDisplayStatus(@PathVariable Long id) {
        Entity entity = entityService.getById(id);
        if (entity == null) {
            return (ResultDTO<EntityStateDisplayDTO>) ResultDTO.error("Entity not found");
        }

        EntityStateDisplayDTO dto = new EntityStateDisplayDTO();
        dto.setId(entity.getId());
        dto.setType(entity.getType().toString());
        dto.setHostIdentity(entity.getHostIdentity());
        dto.setUserIdentity(entity.getUserIdentity());
        dto.setProcessingStage(entity.getProcessingStage());
        dto.setProcessingCode(entity.getProcessingCode());
        dto.setUpdatedAt(entity.getUpdatedAt());

        // Map display status from reprocessState and processingStage.
        String displayStatus = mapToDisplayStatus(entity);
        dto.setDisplayStatus(displayStatus);

        return ResultDTO.success(dto);
    }

    private String mapToDisplayStatus(Entity entity) {
        ReprocessState reprocessState = entity.getReprocessState();
        if (reprocessState == null) {
            reprocessState = ReprocessState.NONE;
        }

        switch (reprocessState) {
            case INIT:
                return "init";
            case RUNNING:
                return "running";
            case SUCCESS:
                // Count as enforced only when reprocessState=SUCCESS, processingStage=ENFORCED, and processingCode=0.
                if ("ENFORCED".equals(entity.getProcessingStage()) &&
                    (entity.getProcessingCode() == null || entity.getProcessingCode() == 0)) {
                    return "enforced";
                } else {
                    return "failed";
                }
            case FAILED:
                return "failed";
            case NONE:
            default:
                // If reprocessState is missing, derive display status directly from processingStage.
                if ("ENFORCED".equals(entity.getProcessingStage()) &&
                    (entity.getProcessingCode() == null || entity.getProcessingCode() == 0)) {
                    return "enforced";
                } else {
                    return entity.getProcessingStage() != null ? entity.getProcessingStage().toLowerCase() : "unknown";
                }
        }
    }
}

content.text:
现在我有了完整的上下文：
- **EntityStage** 值: PENDING → LABELED → EVALUATED → ENFORCED
- **mapToDisplayStatus 逻辑**已在 `EntityController` 中（line 56-87），需要迁移到 DTO
- **displayStatus** 依赖 `reprocessState` + `processingStage`
- **DeviceTypeChangedHandler** 已调用不存在的 `cacheEntity()` — 一并修复

## 设计方案

**改动点（5处文件，方案如下）：**

---

### 1. `EntityStateDisplayDTO` — 加 static factory（迁移 Controller 的映射逻辑）

从 `EntityController.mapToDisplayStatus()` 迁移，让 DTO 自持转换：

```java
// 新增 import
import com.fortinet.nac.ingestion.entity.Entity;
import com.fortinet.nac.common.enums.ReprocessState;

// 新增静态工厂 + displayStatus 推导
public static EntityStateDisplayDTO from(Entity entity) {
    return new EntityStateDisplayDTO(
        entity.getId(),
        entity.getType() != null ? entity.getType().toString() : null,
        entity.getHostIdentity(),
        entity.getUserIdentity(),
        entity.getProcessingStage(),
        entity.getProcessingCode(),
        entity.getUpdatedAt(),
        deriveDisplayStatus(entity)
    );
}

private static String deriveDisplayStatus(Entity entity) {
    ReprocessState reprocessState = entity.getReprocessState();
    if (reprocessState == null) reprocessState = ReprocessState.NONE;
    switch (reprocessState) {
        case INIT:    return "init";
        case RUNNING: return "running";
        case SUCCESS:
            return isEnforced(entity) ? "enforced" : "failed";
        case FAILED:  return "failed";
        case NONE: default:
            return isEnforced(entity)
                ? "enforced"
                : (entity.getProcessingStage() != null
                    ? entity.getProcessingStage().toLowerCase()
                    : "unknown");
    }
}

private static boolean isEnforced(Entity entity) {
    return "ENFORCED".equals(entity.getProcessingStage())
        && (entity.getProcessingCode() == null || entity.getProcessingCode() == 0);
}
```

---

### 2. `EntityCache` — 加 in-memory display cache

**Key 策略**：in-memory map 用 `entityId.toString()` 作 key（Controller 按 ID 查询），Redis bucket 仍用 `existKey`（Handler 按请求查询）。两套 key 各自服务各自的访问路径。

```java
// 新增 import
import com.fortinet.nac.ingestion.dto.EntityStateDisplayDTO;
import com.fortinet.nac.ingestion.entity.Entity;
import java.util.Collections;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

// 新增字段
private final Map<String, EntityStateDisplayDTO> displayCache = new ConcurrentHashMap<>();

// 新增方法 1：同时写 Redis ID + in-memory display（修复 DeviceTypeChangedHandler 的调用缺口）
public void cacheEntity(String existKey, Entity entity, int ttl) {
    cacheEntityId(existKey, entity.getId(), ttl);
    displayCache.put(entity.getId().toString(), EntityStateDisplayDTO.from(entity));
}

// 新增方法 2：Controller 按 entityId 查 display view
public EntityStateDisplayDTO getDisplayView(Long entityId) {
    return displayCache.get(entityId.toString());
}

// 新增方法 3：显式失效（type change、数据不一致时可用）
public void invalidateDisplayView(Long entityId) {
    displayCache.remove(entityId.toString());
}

// 新增方法 4：全量快照（监控/调试用）
public Map<String, EntityStateDisplayDTO> getAllDisplayViews() {
    return Collections.unmodifiableMap(displayCache);
}

// 修改：clear() 同时清 display cache
public void clear() {
    redissonClient.getKeys().flushdb();
    displayCache.clear();
}
```

---

### 3. `NewEntityHandler` line 84 — 替换调用

```java
// before
entityCache.cacheEntityId(key, entity.getId(), Constants.RedisKeys.ENTITY_EXIST_KEY_TTL);
// after
entityCache.cacheEntity(key, entity, Constants.RedisKeys.ENTITY_EXIST_KEY_TTL);
```

log 消息同步更新：`"Failed to cache entityId"` → `"Failed to cache entity"`

---

### 4. `IngestionOrchestrator` line 63 — 替换调用

```java
// before
entityCache.cacheEntityId(existKey, dbEntity.getId(), Constants.RedisKeys.ENTITY_EXIST_KEY_TTL);
// after
entityCache.cacheEntity(existKey, dbEntity, Constants.RedisKeys.ENTITY_EXIST_KEY_TTL);
```

---

### 5. `EntityController` — 注入 EntityCache，cache-first 读取，删除冗余逻辑

```java
@Resource
private EntityCache entityCache;

@GetMapping("/{id}/display-status")
public ResultDTO<EntityStateDisplayDTO> getEntityDisplayStatus(@PathVariable Long id) {
    EntityStateDisplayDTO cached = entityCache.getDisplayView(id);
    if (cached != null) {
        return ResultDTO.success(cached);
    }
    Entity entity = entityService.getById(id);
    if (entity == null) {
        return (ResultDTO<EntityStateDisplayDTO>) ResultDTO.error("Entity not found");
    }
    return ResultDTO.success(EntityStateDisplayDTO.from(entity));
}
// 删除 mapToDisplayStatus() — 逻辑已迁移到 EntityStateDisplayDTO.deriveDisplayStatus()
```

---

## 设计说明与权衡

| 项 | 说明 |
|---|---|
| **Key 策略** | display map 用 `entityId`，Redis 用 `existKey`；两路访问模式不同，各自最优 |
