### 1. `EntityStateDisplayDTO` — 加 static factory（迁移 Controller 的映射逻辑）

从 `EntityController.mapToDisplayStatus()` 迁移，让 DTO 自持转换：

```java
// 新增 import
import com.fortinet.nac.ingestion.entity.Entity;
import com.fortinet.nac.common.enums.ReprocessState;

// 新增静态工厂 + displayStatus 推导
public static EntityStateDisplayDTO from(Entity entity) {
    return new EntityStateDisplayDTO(
        entity.getId(),
        entity.getType() != null ? entity.getType().toString() : null,
        entity.getHostIdentity(),
        entity.getUserIdentity(),
        entity.getProcessingStage(),
        entity.getProcessingCode(),
        entity.getUpdatedAt(),
        deriveDisplayStatus(entity)
    );
}

private static String deriveDisplayStatus(Entity entity) {
    ReprocessState reprocessState = entity.getReprocessState();
    if (reprocessState == null) reprocessState = ReprocessState.NONE;
    switch (reprocessState) {
        case INIT:    return "init";
        case RUNNING: return "running";
        case SUCCESS:
            return isEnforced(entity) ? "enforced" : "failed";
        case FAILED:  return "failed";
        case NONE: default:
            return isEnforced(entity)
                ? "enforced"
                : (entity.getProcessingStage() != null
                    ? entity.getProcessingStage().toLowerCase()
                    : "unknown");
    }
}

private static boolean isEnforced(Entity entity) {
    return "ENFORCED".equals(entity.getProcessingStage())
        && (entity.getProcessingCode() == null || entity.getProcessingCode() == 0);
}
```

