```java
@Resource
private EntityCache entityCache;

@GetMapping("/{id}/display-status")
public ResultDTO<EntityStateDisplayDTO> getEntityDisplayStatus(@PathVariable Long id) {
    EntityStateDisplayDTO cached = entityCache.getDisplayView(id);
    if (cached != null) {
        return ResultDTO.success(cached);
    }
    Entity entity = entityService.getById(id);
    if (entity == null) {
        return (ResultDTO<EntityStateDisplayDTO>) ResultDTO.error("Entity not found");
    }
    return ResultDTO.success(EntityStateDisplayDTO.from(entity));
}
// 删除 mapToDisplayStatus() — 逻辑已迁移到 EntityStateDisplayDTO.deriveDisplayStatus()
